import React, { useEffect, useRef } from 'react';

const NODE_RADIUS = 25;
const LEVEL_HEIGHT = 80;
const NODE_SPACING = 60;

export default function HeapView({ data }) {
  const canvasRef = useRef(null);

  const drawNode = (ctx, x, y, node, isMin) => {
    // Draw circle
    ctx.beginPath();
    ctx.arc(x, y, NODE_RADIUS, 0, 2 * Math.PI);
    ctx.fillStyle = isMin ? '#ffeb3b' : '#fff';
    ctx.fill();
    ctx.strokeStyle = '#2196f3';
    ctx.lineWidth = 2;
    ctx.stroke();

    // Draw text
    ctx.fillStyle = '#000';
    ctx.font = '14px Arial';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText(`${node.key}`, x, y);
  };

  const drawConnection = (ctx, x1, y1, x2, y2) => {
    ctx.beginPath();
    ctx.moveTo(x1, y1 + NODE_RADIUS);
    ctx.lineTo(x2, y2 - NODE_RADIUS);
    ctx.strokeStyle = '#90caf9';
    ctx.lineWidth = 2;
    ctx.stroke();
  };

  const calculatePositions = (nodes, roots) => {
    const positions = new Map();
    let currentX = 50;
    
    // Position root nodes
    roots.forEach(rootId => {
      const node = nodes.find(n => n.id === rootId);
      if (node) {
        positions.set(rootId, { x: currentX, y: 50 });
        currentX += NODE_SPACING * 2;
        
        // Position children recursively
        if (node.children && node.children.length) {
          let childX = currentX - NODE_SPACING * 1.5;
          node.children.forEach(childId => {
            const childNode = nodes.find(n => n.id === childId);
            if (childNode) {
              positions.set(childId, { x: childX, y: 50 + LEVEL_HEIGHT });
              childX += NODE_SPACING;
            }
          });
        }
      }
    });

    return positions;
  };

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    const positions = calculatePositions(data.nodes || [], data.roots || []);

    // Clear canvas
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Draw connections first
    data.nodes?.forEach(node => {
      const pos = positions.get(node.id);
      if (pos && node.children) {
        node.children.forEach(childId => {
          const childPos = positions.get(childId);
          if (childPos) {
            drawConnection(ctx, pos.x, pos.y, childPos.x, childPos.y);
          }
        });
      }
    });

    // Draw nodes
    data.nodes?.forEach(node => {
      const pos = positions.get(node.id);
      if (pos) {
        drawNode(ctx, pos.x, pos.y, node, node.id === data.min);
      }
    });
  }, [data]);

  return (
    <div style={{ marginTop: 20, border: '1px solid #ccc', padding: 10 }}>
      <canvas 
        ref={canvasRef}
        width={800}
        height={400}
        style={{ background: '#f8f8f8' }}
      />
    </div>
  );
}
